pre_install:
$script = @'
param([string]$cmd)

$port = 8080

switch ($cmd) {
    "start" {
        Write-Host "Starting phpMyAdmin at http://localhost:$port"
        Start-Process php -ArgumentList "-S localhost:$port" -WorkingDirectory "$PSScriptRoot"
    }

    "stop" {
        Get-Process php -ErrorAction SilentlyContinue | Stop-Process -Force
        Write-Host "phpMyAdmin stopped"
    }

    "open" {
        Start-Process "http://localhost:$port"
    }

    default {
        Write-Host "phpMyAdmin Scoop Manager"
        Write-Host ""
        Write-Host "Usage:"
        Write-Host "  phpmyadmin start   Start phpMyAdmin"
        Write-Host "  phpmyadmin stop    Stop phpMyAdmin"
        Write-Host "  phpmyadmin open    Open browser"
    }
}
'@
Set-Content "$dir\phpmyadmin.ps1" $script
